app.use(express.urlencoded({ extended: true }));

const PORT = process.env.PORT || 3000;
const BACKEND_BASE_URL = process.env.BACKEND_BASE_URL || 'http://localhost:4000';
const DEFAULT_API_KEY_HEADER = process.env.API_KEY_HEADER || 'x-api-key';

function getTargetUrl(req) {
  const incomingUrl = new URL(req.originalUrl, `http://${req.headers.host || 'localhost'}`);
  const targetBase = new URL(BACKEND_BASE_URL);
  const target = new URL(targetBase.toString());

  target.pathname = req.originalUrl.split('?')[0];
  target.search = incomingUrl.search;
  return target;
}

function chooseClient(urlObj) {
  return urlObj.protocol === 'https:' ? https : http;
}

function buildHeaders(req, apiKey) {
  const headers = { ...req.headers };
  delete headers.host;
  delete headers['content-length'];
  delete headers['connection'];

  if (apiKey) {
    headers[DEFAULT_API_KEY_HEADER.toLowerCase()] = apiKey;
  }

  if (headers['x-forwarded-for']) {
    headers['x-forwarded-for'] += `, ${req.ip}`;
  } else {
    headers['x-forwarded-for'] = req.ip;
  }

  headers['x-forwarded-proto'] = req.protocol;
  headers['x-forwarded-host'] = req.headers.host || '';

  return headers;
}

